# data/rosters.py

def calculate_ovr(p):
    # Para leyendas, su OVR es directamente su potencial (pico de carrera)
    try:
        is_legend = bool(p.get("is_legend", False))
    except:
        is_legend = False
        
    if is_legend:
        try:
            return int(p.get("pot", 90))
        except (ValueError, TypeError):
            return 90
        
    s = p.get("s", {})
    
    def _safe_stat(key, default_val=70):
        try:
            return int(s.get(key, default_val))
        except (ValueError, TypeError):
            return default_val

    pos = str(p.get("pos", "CM"))
    
    if pos == "GK":
        return _safe_stat("gk", 80)
    
    # 6 Stats: speed, shot, passing, dribbling, defense, physical
    spd = _safe_stat("speed", 70)
    sht = _safe_stat("shot", 70)
    pas = _safe_stat("passing", 70)
    dri = _safe_stat("dribbling", 70)
    dfn = _safe_stat("defense", 70)
    phy = _safe_stat("physical", 70)
    
    if pos in ["CB", "LB", "RB"]:
        # Defensas: Defensa es lo más importante
        return int(dfn * 0.6 + phy * 0.2 + spd * 0.1 + pas * 0.1)
    elif pos == "CDM":
        # Mediocentros Defensivos: Defensa y Físico importan
        return int(dfn * 0.4 + pas * 0.3 + phy * 0.2 + spd * 0.1)
    elif pos in ["CM", "CAM"]:
        # Medios: Pase y Regate dominan
        return int(pas * 0.5 + dri * 0.3 + spd * 0.1 + sht * 0.1)
    else: # ST, LW, RW
        # Delanteros: Tiro y Velocidad dominan
        return int(sht * 0.5 + spd * 0.25 + dri * 0.2 + pas * 0.05)

