    for tid, players in rosters.items():
        for p in players:
            p["team"] = tid
            ovr = calculate_ovr(p)
            p["ovr"] = ovr
            if ovr >= 75: p["rarity"] = "ORO"
            elif ovr >= 65: p["rarity"] = "PLATA"
            else: p["rarity"] = "BRONCE"
            p["is_legend"] = False
            

